	// incrementally. Even if the test is killed by a global timeout,
	// partial output survives.
	artDir := artifactDir(t)
	consoleLog, err := os.Create(filepath.Join(artDir, "console.log"))
	if err != nil {
		t.Fatalf("create console.log: %v", err)
	}

